import{_ as u,C as i,o as p,c as h,a6 as d,E as t,j as o,a,w as s}from"./chunks/framework.DtxWasON.js";const w=JSON.parse('{"title":"Network Upgrade: 5-pike","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/migrations/5-pike_upgrade.md","filePath":"mainchain/migrations/5-pike_upgrade.md"}'),m={name:"mainchain/migrations/5-pike_upgrade.md"};function g(v,e,k,b,f,_){const l=i("InstallUnd"),n=i("CosmovisorDirTree"),r=i("PluginTabsTab"),c=i("PluginTabs");return p(),h("div",null,[e[4]||(e[4]=d('<h1 id="network-upgrade-5-pike" tabindex="-1">Network Upgrade: 5-pike <a class="header-anchor" href="#network-upgrade-5-pike" aria-label="Permalink to &quot;Network Upgrade: 5-pike&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p><strong>TestNet</strong> was successfully upgraded to <code>5-pike</code> in block <strong>13,910,300</strong></p><p><strong>MainNet</strong> was successfully upgraded to <code>5-pike</code> in block <strong>12,210,000</strong></p></div><div class="tip custom-block"><p class="custom-block-title">Note</p><p>This guide is for operators already running a node, and only for <strong>before</strong> the upgrade&#39;s target block height.</p><p>For new nodes or upgrades <strong>after</strong> the upgrade&#39;s target block height, please see the <a href="./../software/cosmovisor/install_und_with_cosmovisor.html">Install und with Cosmovisor</a> documentation.</p></div><p>There are two possible methods for upgrading:</p><ol><li>Automatically, using Cosmovisor (recommended)</li><li>Manually</li></ol><h2 id="automatically-upgrade-from-und-v1-9-x-to-v1-10-x-using-cosmovisor" tabindex="-1">Automatically upgrade from und v1.9.x to v1.10.x using Cosmovisor <a class="header-anchor" href="#automatically-upgrade-from-und-v1-9-x-to-v1-10-x-using-cosmovisor" aria-label="Permalink to &quot;Automatically upgrade from und v1.9.x to v1.10.x using Cosmovisor&quot;">​</a></h2><p><strong>IMPORTANT:</strong> This guide assumes the reader has implemented the required changes outlined in <a href="./cosmovisor.html">Using Cosmovisor with und: Quick Start</a> and migrated their services before using this guide.</p><h3 id="configuring-cosmovisor" tabindex="-1">Configuring Cosmovisor <a class="header-anchor" href="#configuring-cosmovisor" aria-label="Permalink to &quot;Configuring Cosmovisor&quot;">​</a></h3><p>The following can be implemented well in advance of the actual upgrade occurring, which will allow for a completely automated upgrade.</p><p><strong>IMPORTANT</strong> During the upgrade, <code>cosmovisor</code> will automatically do a full backup of the <code>.und_mainchain/data</code> directory. Ensure your host has adequate disk space to accommodate the backup. This may add significant time to the upgrade process, and as such, the process may take up to 30 minutes before the node comes back online.</p><h4 id="_1-create-the-cosmovisor-upgrade-plan-directory" tabindex="-1">1. Create the Cosmovisor upgrade plan directory <a class="header-anchor" href="#_1-create-the-cosmovisor-upgrade-plan-directory" aria-label="Permalink to &quot;1. Create the Cosmovisor upgrade plan directory&quot;">​</a></h4><p>This will be dependent on how you configured <code>cosmovisor</code>, and your actual <code>.und_mainchain</code> path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.und_mainchain/cosmovisor/upgrades/5-pike/bin</span></span></code></pre></div><h4 id="_2-download-the-latest-und-v1-10-x-and-add-to-cosmovisor-s-upgrades-directory" tabindex="-1">2. Download the latest <code>und</code> v1.10.x and add to Cosmovisor&#39;s <code>upgrades</code> directory <a class="header-anchor" href="#_2-download-the-latest-und-v1-10-x-and-add-to-cosmovisor-s-upgrades-directory" aria-label="Permalink to &quot;2. Download the latest `und` v1.10.x and add to Cosmovisor&#39;s `upgrades` directory&quot;">​</a></h4>',14)),t(l,{version:"1.10.1",plan:"5-pike"}),e[5]||(e[5]=o("p",null,[a("Check the version output is "),o("code",null,"1.10.1"),a("!")],-1)),e[6]||(e[6]=o("p",null,[a("The directory structure for "),o("code",null,"$HOME/.und_mainchain/cosmovisor"),a(" should now look as follows:")],-1)),t(c,null,{default:s(()=>[t(r,{label:"MainNet"},{default:s(()=>[e[0]||(e[0]=o("h4",{id:"mainnet",tabindex:"-1"},[a("MainNet "),o("a",{class:"header-anchor",href:"#mainnet","aria-label":'Permalink to "MainNet"'},"​")],-1)),e[1]||(e[1]=o("p",null,[o("strong",null,"Note:"),a(" 1st upgrade path name is "),o("code",null,"1-init_ibc")],-1)),t(n,{network:"mainnet",plan:"5-pike",upgraded:"false"})]),_:1}),t(r,{label:"TestNet"},{default:s(()=>[e[2]||(e[2]=o("h4",{id:"testnet",tabindex:"-1"},[a("TestNet "),o("a",{class:"header-anchor",href:"#testnet","aria-label":'Permalink to "TestNet"'},"​")],-1)),e[3]||(e[3]=o("p",null,[o("strong",null,"Note:"),a(" 1st upgrade path name is "),o("code",null,"1-ibc")],-1)),t(n,{network:"testnet",plan:"5-pike",upgraded:"true"})]),_:1})]),_:1}),e[7]||(e[7]=d('<p>That&#39;s it! When the upgrade height specified in the governance proposal is reached, Cosmovisor and the <code>upgrade</code> module will handle the rest automatically.</p><h3 id="cosmovisor-upgrade-process-overview" tabindex="-1">Cosmovisor Upgrade process overview <a class="header-anchor" href="#cosmovisor-upgrade-process-overview" aria-label="Permalink to &quot;Cosmovisor Upgrade process overview&quot;">​</a></h3><p>Briefly, at the upgrade height, Cosmovisor will automatically:</p><ol><li>Stop the <code>und</code> v1.9.x binary</li><li>Backup <code>.und_mainchain/data</code> to <code>.und_mainchain/data-backup-YYYY-M-DD</code><strong>*</strong></li><li>Reconfigure itself to use <code>und</code> v1.10.x</li><li>Restart <code>und</code> using the new version</li></ol><p><strong>*Ensure the host has enough space to back up!</strong></p><h2 id="manual-upgrade-not-recommended" tabindex="-1">Manual upgrade (not recommended) <a class="header-anchor" href="#manual-upgrade-not-recommended" aria-label="Permalink to &quot;Manual upgrade (not recommended)&quot;">​</a></h2><p>The alternative to implementing Cosmovisor is to manually upgrade the binary. Once the upgrade height specified in the governance proposal is reached, the <code>upgrade</code> module will automatically halt the node via a <code>panic</code>. The node operator will then need to:</p><ol><li>Stop the <code>und</code> v1.9.x binary, via <code>systemd</code> or their chosen method</li><li>Backup the <code>und_mainchain/data</code> directory</li><li>Download and install the latest <code>und</code> v1.10.x, replacing the old v1.9.x binary (for example in <code>/usr/local/bin</code>)</li><li>Restart the <code>und</code> binary, via <code>systemd</code> or their chosen method.</li></ol><p>Since the process involves manual intervention, monitoring and execution, the process may take longer.</p>',9))])}const T=u(m,[["render",g]]);export{w as __pageData,T as default};
